public class TwoStacksInArray {

    private int[] data;
    private int top1, top2;

    public TwoStacksInArray(int capacity) {
        data = new int[capacity];
        top1 = -1;
        top2 = capacity;
    }

    public void push(int stackNum, int val) {
        if (top1 + 1 == top2) throw new RuntimeException("Both stacks full");
        if (stackNum == 1) {
            data[++top1] = val;
        } else {
            // TODO: stack 2 grows rightward, decrement top2, store val
        }
    }

    public int pop(int stackNum) {
        if (stackNum == 1) {
            if (top1 == -1) throw new RuntimeException("Stack 1 empty");
            return data[top1--];
        } else {
            // TODO: stack 2 pop
            return -1;
        }
    }

    public int peek(int stackNum) {
        if (stackNum == 1) return data[top1];
        return data[top2];
    }

    public static void main(String[] args) {
        TwoStacksInArray ts = new TwoStacksInArray(10);
        ts.push(1, 10); ts.push(1, 20);
        ts.push(2, 100); ts.push(2, 200);
        System.out.println("S1 peek: " + ts.peek(1));
        System.out.println("S2 peek: " + ts.peek(2));
        System.out.println("S1 pop: " + ts.pop(1));
        System.out.println("S2 pop: " + ts.pop(2));
    }
}
